def find_user_by_email(email):
    try:
        client = MongoClient('mongodb://localhost:27017/')
        db = client['mydatabase']
        collection = db['users']

        user = collection.find_one({'email': email})
        
        if user is not None:
            return user
        else:
            return None

    except Exception as e:
        print(f"Error finding user by email: {e}")
        return None

